func writeTempGo(t *testing.T, content string) string {
	t.Helper()
	dir := t.TempDir()
	path := filepath.Join(dir, "fixture.go")
	if err := os.WriteFile(path, []byte(content), 0644); err != nil {
		t.Fatal(err)
	}
	return path
}

func TestParseCleanLevel(t *testing.T) {
	for _, n := range []int{1, 2, 3} {
		if _, err := ParseCleanLevel(n); err != nil {
			t.Errorf("ParseCleanLevel(%d) error: %v", n, err)
		}
	}
	for _, n := range []int{0, 4, -1, 99} {
		if _, err := ParseCleanLevel(n); err == nil {
			t.Errorf("ParseCleanLevel(%d) should reject", n)
		}
	}
}

// Level 1：移除所有 @ai；func 無 @<human> 標記 → 描述行也移除
func TestCleanFile_Level1_RemovesAll_StripsDescriptionWhenNoHumanMarker(t *testing.T) {
	src := `package example

// CreateUser 建立使用者並寫進資料庫。
//
// @ai:generated by=claude-opus-4-8 date=2026-06-18
// @ai:purpose 提供 REST API 建立帳號
// @ai:input JSON body
// @ai:output 201 + UserResp
// @ai:sideeffect DB insert
func CreateUser() {
	//@ai:think intent=先驗證 email 唯一性 model=claude-opus-4-8
	println("ok")
}
`
	path := writeTempGo(t, src)
	report, err := CleanFile(path, CleanLevelAll)
	if err != nil {
		t.Fatal(err)
	}
	if !report.Modified {
		t.Fatal("expected file to be modified")
	}

	data, _ := os.ReadFile(path)
	out := string(data)
	if strings.Contains(out, "@ai:") {
		t.Errorf("level 1 should remove all @ai, got:\n%s", out)
	}
	// 描述也應被移除（無 @human）
	if strings.Contains(out, "CreateUser 建立使用者並寫進資料庫") {
		t.Errorf("description should be removed (no human marker), got:\n%s", out)
	}
	// 但 func 本體應保留
	if !strings.Contains(out, "func CreateUser()") {
		t.Errorf("func declaration should remain, got:\n%s", out)
	}
	if !strings.Contains(out, `println("ok")`) {
		t.Errorf("func body code should remain, got:\n%s", out)
	}
	// .bak 應該存在
	if _, err := os.Stat(report.BackupPath); err != nil {
		t.Errorf("backup should exist: %v", err)
	}
}

