// 無 @ai 註釋 → 不修改、不建 .bak
func TestCleanFile_NoChangesWhenNoAITagsPresent(t *testing.T) {
	src := `package example

// Plain 是純人類撰寫的註釋。
func Plain() {
	println("ok")
}
`
	path := writeTempGo(t, src)
	original, _ := os.ReadFile(path)

	report, err := CleanFile(path, CleanLevelAll)
	if err != nil {
		t.Fatal(err)
	}
	if report.Modified {
		t.Error("should not modify file when no @ai tags")
	}
	if report.Removed != 0 {
		t.Errorf("Removed = %d, want 0", report.Removed)
	}

	current, _ := os.ReadFile(path)
	if string(current) != string(original) {
		t.Error("file content should be unchanged")
	}
	// .bak 不應該被建立
	if _, err := os.Stat(path + ".bak"); err == nil {
		t.Error("backup should NOT be created when no changes")
	}
}

