// CleanDir 應該遞迴處理子目錄並跳過 vendor/
func TestCleanDir_RecursesAndSkipsVendor(t *testing.T) {
	root := t.TempDir()

	mkfile := func(rel, content string) {
		full := filepath.Join(root, rel)
		os.MkdirAll(filepath.Dir(full), 0755)
		if err := os.WriteFile(full, []byte(content), 0644); err != nil {
			t.Fatal(err)
		}
	}

	withAI := `package x
// Foo
// @ai:generated by=x date=2026-06-18
func Foo() {}
`
	mkfile("a.go", withAI)
	mkfile("sub/b.go", withAI)
	mkfile("vendor/c.go", withAI) // 應被跳過
	mkfile(".hyp/d.go", withAI)   // 應被跳過

	reports, err := CleanDir(root, CleanLevelAll)
	if err != nil {
		t.Fatal(err)
	}

	cleanedSet := map[string]bool{}
	for _, r := range reports {
		if r.Modified {
			rel, _ := filepath.Rel(root, r.Filename)
			cleanedSet[filepath.ToSlash(rel)] = true
		}
	}

	if !cleanedSet["a.go"] {
		t.Error("a.go should be cleaned")
	}
	if !cleanedSet["sub/b.go"] {
		t.Error("sub/b.go should be cleaned")
	}
	if cleanedSet["vendor/c.go"] {
		t.Error("vendor/c.go should be skipped")
	}
	if cleanedSet[".hyp/d.go"] {
		t.Error(".hyp/d.go should be skipped")
	}
}

func TestExtractAITag(t *testing.T) {
	tests := []struct {
		line    string
		wantTag string
		wantOK  bool
	}{
		{"// @ai:generated by=x", "generated", true},
		{"//@ai:think intent=xyz", "think", true},
		{"\t//@ai:think special=abc", "think", true},
		{"// @ai:purpose foo", "purpose", true},
		{"// just a comment", "", false},
		{"// @chris hello", "", false},
		{"//@ai:", "", true}, // 邊界：空 tag 名（但有 @ai: 前綴）
		{"  //  @ai:input foo  ", "input", true},
	}
	for _, tt := range tests {
		got, ok := extractAITag(tt.line)
		if ok != tt.wantOK {
			t.Errorf("extractAITag(%q) ok = %v, want %v", tt.line, ok, tt.wantOK)
		}
		if ok && got != tt.wantTag {
			t.Errorf("extractAITag(%q) = %q, want %q", tt.line, got, tt.wantTag)
		}
	}
}
